const data = $('Parse Response').first().json;
const apiError = data.apiError || 'Unknown error';

let errorExplanation = '';
const errorLower = apiError.toLowerCase();

if (errorLower.includes('timeout')) {
  errorExplanation = 'WhatsApp service timed out.';
} else if (errorLower.includes('invalid number')) {
  errorExplanation = 'Invalid or unregistered WhatsApp number.';
} else if (errorLower.includes('rate limit')) {
  errorExplanation = 'Rate limit exceeded. Wait a few minutes.';
} else if (errorLower.includes('blocked')) {
  errorExplanation = 'Number may have blocked messages.';
} else {
  errorExplanation = 'Unexpected WhatsApp API error.';
}

const errorMessage = `❌ Failed to send message to ${data.contactName}

🔍 Issue: ${errorExplanation}
📱 Recipient: ${data.contactName} (${data.phone})
⚠️ Error: ${apiError}

💡 Please verify the phone number and try again.`;

return [{
  json: {
    success: false,
    message: errorMessage,
    details: {
      recipient: data.contactName,
      phone: data.phone,
      error: apiError,
      timestamp: data.timestamp
    }
  }
}];

