// Extract LinkedIn post URN from social_id
const socialId = $input.item.json.social_id;
let shareUrn = '';

// Parse social_id to get the post URN
if (typeof socialId === 'string') {
  try {
    const parsed = JSON.parse(socialId);
    const location = parsed.location || parsed['x-restli-id'];

    if (location) {
      // Extract URN from location or x-restli-id
      // Handle URL-encoded URN in location
      const decodedLocation = decodeURIComponent(location);
      const match = decodedLocation.match(/urn:li:share:\d+/);
      if (match) {
        shareUrn = match[0];
      }
    }
  } catch (e) {
    // If it's already a URN string
    const match = socialId.match(/urn:li:share:\d+/);
    if (match) {
      shareUrn = match[0];
    }
  }
}

// Get access token from auth object (direct access since data is merged)
const accessToken = $input.item.json.auth?.access_token || '';

// Get post ID (using the content_calendar id field)
const postId = $input.item.json.id;

// Validation
if (!shareUrn) {
  throw new Error(`Could not extract LinkedIn share URN from social_id: ${socialId}`);
}

if (!accessToken) {
  throw new Error('Access token not found in social account data');
}

// Return the data needed for deletion
