  shareUrn: shareUrn,
  accessToken: accessToken,
  postId: postId,
  newContent: newContent,
  mediaUrls: newMediaUrls,
  organizationId: organizationId,
  handle: $input.item.json.handle
};

// Build the LinkedIn API update payload
const content = $input.item.json.newContent;
const mediaUrls = $input.item.json.mediaUrls || [];
const organizationId = $input.item.json.organizationId;

// Build the specificContent object
let specificContent = {
  "com.linkedin.ugc.ShareContent": {
    "shareCommentary": {
      "text": content
    },
    "shareMediaCategory": mediaUrls.length > 0 ? "IMAGE" : "NONE"
  }
};

// Add media if provided
if (mediaUrls.length > 0) {
  specificContent["com.linkedin.ugc.ShareContent"].media = mediaUrls.map(url => ({
    "status": "READY",
    "media": url,
    "title": {
      "text": "Image"
    }
  }));
}

// Build the full payload for LinkedIn API v2
const payload = {
  "patch": {
    "$set": {
      "specificContent": specificContent,
      "text": {
        "text": content
      }
    }
  }
};

return {
  ...($input.item.json),
  payload: payload
};

